import React, { useState } from "react";

const Report = () => {
  const [viewMode, setViewMode] = useState("monthly");

  // Dữ liệu mock
  const monthlyRevenue = [
    { Nam: 2025, Thang: 1, DoanhThu: 1000000 },
    { Nam: 2025, Thang: 2, DoanhThu: 1200000 },
  ];
  const yearlyRevenue = [
    { Nam: 2024, DoanhThu: 12000000 },
    { Nam: 2025, DoanhThu: 15000000 },
  ];
  const topCustomers = [
    { MaKH: "KH01", HoTen: "Nguyen Van A", SoLanDat: 5, TongChiTieu: 5000000 },
    { MaKH: "KH02", HoTen: "Tran Thi B", SoLanDat: 3, TongChiTieu: 3000000 },
  ];
  const roomUsage = [
    { PhongSo: "101", SoLanThue: 10 },
    { PhongSo: "102", SoLanThue: 8 },
  ];

  const renderRevenueTable = () => {
    const data = viewMode === "monthly" ? monthlyRevenue : yearlyRevenue;
    if (!data.length) return <p>Chưa có dữ liệu</p>;

    return (
      <table style={{ borderCollapse: "collapse", width: "100%" }}>
        <thead>
          <tr style={{ backgroundColor: "#cfe2ff" }}>
            {viewMode === "monthly" && <th style={thStyle}>Năm</th>}
            {viewMode === "monthly" && <th style={thStyle}>Tháng</th>}
            <th style={thStyle}>Doanh thu</th>
          </tr>
        </thead>
        <tbody>
          {data.map((row, idx) => (
            <tr
              key={idx}
              style={{ backgroundColor: idx % 2 === 0 ? "#f8f9fa" : "#ffffff" }}
            >
              {viewMode === "monthly" && <td style={tdStyle}>{row.Nam}</td>}
              {viewMode === "monthly" && <td style={tdStyle}>{row.Thang}</td>}
              <td style={tdStyle}>{row.DoanhThu}</td>
            </tr>
          ))}
        </tbody>
      </table>
    );
  };

  const renderTable = (data, columns) => {
    if (!data.length) return <p>Chưa có dữ liệu</p>;

    return (
      <table style={{ borderCollapse: "collapse", width: "100%" }}>
        <thead>
          <tr style={{ backgroundColor: "#d1e7dd" }}>
            {columns.map((col) => (
              <th key={col} style={thStyle}>
                {col}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {data.map((row, idx) => (
            <tr
              key={idx}
              style={{ backgroundColor: idx % 2 === 0 ? "#f8f9fa" : "#ffffff" }}
            >
              {columns.map((col) => (
                <td key={col} style={tdStyle}>
                  {row[col]}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    );
  };

  const Card = ({ title, children }) => (
    <div
      style={{
        border: "1px solid #ccc",
        borderRadius: "8px",
        padding: "16px",
        marginBottom: "20px",
        backgroundColor: "#ffffff",
        boxShadow: "2px 2px 8px rgba(0,0,0,0.1)",
      }}
    >
      <h2 style={{ marginBottom: "12px" }}>{title}</h2>
      {children}
    </div>
  );

  const thStyle = { border: "1px solid #ccc", padding: "8px", textAlign: "center" };
  const tdStyle = { border: "1px solid #ccc", padding: "8px", textAlign: "center" };

  return (
    <div style={{ padding: "24px", backgroundColor: "#f1f3f5", minHeight: "100vh" }}>
      <h1 style={{ textAlign: "center", marginBottom: "24px" }}>Báo cáo tổng hợp</h1>

      <Card title="Doanh thu">
        <div style={{ marginBottom: "12px" }}>
          <label style={{ marginRight: "8px" }}>Xem theo:</label>
          <select
            value={viewMode}
            onChange={(e) => setViewMode(e.target.value)}
          >
            <option value="monthly">Tháng</option>
            <option value="yearly">Năm</option>
          </select>
        </div>
        {renderRevenueTable()}
      </Card>

      <Card title="Top khách hàng">{renderTable(topCustomers, ["MaKH", "HoTen", "SoLanDat", "TongChiTieu"])}</Card>

      <Card title="Công suất phòng">{renderTable(roomUsage, ["PhongSo", "SoLanThue"])}</Card>
    </div>
  );
};

export default Report;
